// ======================================================
// KairoXJS v0.0.2
// ======================================================

window.Kairo = window.Kairo || {};


// ==========================
// Utils
// ==========================

Kairo.conLog = (...a) => console.log(...a);
Kairo.conErr = (...a) => console.error(...a);
Kairo.repeat = (fn, ms) => setInterval(fn, ms);

window.conLog = Kairo.conLog;
window.conErr = Kairo.conErr;
window.repeat = Kairo.repeat;


// ==========================
// DOM Wrapper
// ==========================

const wrap = (el) => ({
  el,

  addClass(c) {
    el?.classList.add(c);
    return this;
  },

  removeClass(c) {
    el?.classList.remove(c);
    return this;
  },

  toggleClass(c) {
    el?.classList.toggle(c);
    return this;
  },

  css(p, v) {
    if (!el) return this;

    if (typeof p === "object") {
      for (let k in p) el.style[k] = p[k];
      return this;
    }

    if (v === undefined) return getComputedStyle(el)[p];

    el.style[p] = v;
    return this;
  },

  text(v) {
    if (!el) return this;
    if (v === undefined) return el.textContent;
    el.textContent = v;
    return this;
  },

  html(v) {
    if (!el) return this;
    if (v === undefined) return el.innerHTML;
    el.innerHTML = v;
    return this;
  },

  val(v) {
    if (!el) return this;
    if (v === undefined) return el.value;
    el.value = v;
    return this;
  },

  click(fn) {
    el?.addEventListener("click", () => fn(wrap(el)));
    return this;
  },

  on(e, fn) {
    el?.addEventListener(e, (ev) => fn(wrap(el), ev));
    return this;
  },

  delay(ms, fn) {
    setTimeout(() => fn(wrap(el)), ms);
    return this;
  },

  remove() {
    el?.remove();
    return this;
  },

  parent() {
    return wrap(el?.parentElement);
  },

  append(child) {
    if (!el) return this;
    el.appendChild(child?.el || child);
    return this;
  },

  prepend(child) {
    if (!el) return this;
    el.prepend(child?.el || child);
    return this;
  }
});


// ==========================
// Selector ($)
// ==========================

Kairo.$ = (s) => {
  if (s?.el) return s;
  if (s instanceof HTMLElement) return wrap(s);

  if (typeof s !== "string") throw new Error("Invalid selector");

  if (s.startsWith("#")) return wrap(document.getElementById(s.slice(1)));
  if (s.startsWith(".")) return wrap(document.getElementsByClassName(s.slice(1)));
  if (/^[a-zA-Z]+$/.test(s)) return wrap(document.getElementsByTagName(s));

  if (s.includes(".")) {
    const [t, c] = s.split(".");
    return wrap(document.querySelectorAll(`${t}.${c}`));
  }

  return wrap(document.querySelector(s));
};

window.$ = Kairo.$;


// ==========================
// Events
// ==========================

Kairo.keyboard = {
  keydown: (fn) => addEventListener("keydown", fn),
  keyup: (fn) => addEventListener("keyup", fn),
};

Kairo.mouse = {
  lmb: (fn) =>
    addEventListener("mousedown", e => e.button === 0 && fn(e)),

  rmb: (fn) =>
    addEventListener("contextmenu", e => {
      e.preventDefault();
      fn(e);
    }),

  mouseup: (fn) => addEventListener("mouseup", fn),
  mousedown: (fn) => addEventListener("mousedown", fn),
  touchdown: (fn) => addEventListener("touchstart", fn),
  touchup: (fn) => addEventListener("touchend", fn),
};

Kairo.browser = {
  docLoaded: (fn) => addEventListener("DOMContentLoaded", fn),

  scrollup: (fn) => {
    let last = scrollY;
    addEventListener("scroll", () => {
      scrollY < last && fn();
      last = scrollY;
    });
  },

  scrolldown: (fn) => {
    let last = scrollY;
    addEventListener("scroll", () => {
      scrollY > last && fn();
      last = scrollY;
    });
  },

  geterror: (fn) => addEventListener("error", fn),
};


// ==========================
// Elements
// ==========================

Kairo.createElement = (t, c = "", i = "", n = "") => {
  const el = document.createElement(t);
  if (c) el.className = c;
  if (i) el.id = i;
  if (n) el.setAttribute("name", n);
  document.body.appendChild(el);
  return wrap(el);
};

Kairo.childCreate = (t, p, c = "", i = "", n = "") => {
  const parent =
    p.startsWith("#")
      ? document.getElementById(p.slice(1))
      : p.startsWith(".")
      ? document.getElementsByClassName(p.slice(1))[0]
      : document.querySelector(p);

  if (!parent) return null;

  const el = document.createElement(t);
  if (c) el.className = c;
  if (i) el.id = i;
  if (n) el.setAttribute("name", n);

  parent.appendChild(el);
  return wrap(el);
};

window.createElement = Kairo.createElement;
window.childCreate = Kairo.childCreate;


// ==========================
// Shortcuts
// ==========================

window.keyboard = Kairo.keyboard;
window.mouse = Kairo.mouse;
window.browser = Kairo.browser;


// ==========================
// Ready
// ==========================

window.KairoReady = true;
console.log("KairoXJS v0.0.2 loaded");
